1	import { useCallback } from 'react';
2	import {
3	  Pressable,
4	  type PressableProps,
5	  type StyleProp,
6	  StyleSheet,
7	  Text,
8	  type ViewStyle,
9	} from 'react-native';
10	import Animated, {
11	  useAnimatedStyle,
12	  useSharedValue,
13	  withSpring,
14	  type WithSpringConfig,
15	} from 'react-native-reanimated';
16	import * as Haptics from 'expo-haptics';
17	import { colors, radii, spacing } from '@/design/tokens';
18	import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
19	import { useReducedMotion } from '@/design/useReducedMotion';
20	import { textStyles } from '@/design/typography';
21	
22	export type ChipProps = {
23	  label: string;
24	  active?: boolean;
25	  onPress?: PressableProps['onPress'];
26	  disabled?: boolean;
27	  style?: StyleProp<ViewStyle>;
28	  accessibilityLabel?: string;
29	  testID?: string;
30	};
31	
32	// Filter chip per docs/design.md §5.1 (horizontal chip row) + §1.2 (primarySoft bg
33	// when selected). Press = spring.soft scale-to-0.97 per §1.4 line 100; haptic uses
34	// `selectionAsync` since toggling is a discrete selection change, not an impact.
35	export function Chip({
36	  label,
37	  active = false,
38	  onPress,
39	  disabled = false,
40	  style,
41	  accessibilityLabel,
42	  testID,
43	}: ChipProps) {
44	  const reduced = useReducedMotion();
45	  const pressed = useSharedValue(0);
46	  const interactive = !disabled && !!onPress;
47	
48	  const animatedStyle = useAnimatedStyle(() => ({
49	    transform: [{ scale: 1 - pressed.value * 0.03 }],
50	  }));
51	
52	  const handlePressIn = useCallback(() => {
53	    if (!interactive) return;
54	    void Haptics.selectionAsync();
55	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
56	  }, [interactive, pressed, reduced]);
57	
58	  const handlePressOut = useCallback(() => {
59	    if (!interactive) return;
60	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
61	  }, [interactive, pressed, reduced]);
62	
63	  const bg = disabled ? colors.hairline : active ? colors.primarySoft : colors.surface;
64	  const borderColor = disabled ? colors.ink40 : colors.ink;
65	  const textColor = disabled ? colors.ink40 : active ? colors.primaryDeep : colors.ink;
66	
67	  return (
68	    <Pressable
69	      onPress={interactive ? onPress : undefined}
70	      onPressIn={handlePressIn}
71	      onPressOut={handlePressOut}
72	      disabled={!interactive}
73	      accessibilityRole="button"
74	      accessibilityLabel={accessibilityLabel ?? label}
75	      accessibilityState={{ selected: active, disabled: !interactive }}
76	      testID={testID}
77	    >
78	      <Animated.View
79	        style={[styles.base, { backgroundColor: bg, borderColor }, animatedStyle, style]}
80	      >
81	        <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
82	          {label}
83	        </Text>
84	      </Animated.View>
85	    </Pressable>
86	  );
87	}
88	
89	const styles = StyleSheet.create({
90	  base: {
91	    minHeight: 32,
92	    paddingHorizontal: spacing.md,
93	    paddingVertical: spacing.xs + 2,
94	    borderRadius: radii.pill,
95	    borderWidth: 2,
96	    alignItems: 'center',
97	    justifyContent: 'center',
98	    flexDirection: 'row',
99	  },
100	});
