1	import { StyleSheet, Text, View, type StyleProp, type ViewStyle } from 'react-native';
2	import { colors, radii, spacing } from '@/design/tokens';
3	import { textStyles } from '@/design/typography';
4	
5	export type StatusPillStatus = 'pending' | 'approved' | 'rejected' | 'cancelled';
6	
7	export type StatusPillProps = {
8	  status: StatusPillStatus;
9	  label?: string;
10	  style?: StyleProp<ViewStyle>;
11	  testID?: string;
12	};
13	
14	// Read-only status pill — semantic color trio per docs/design.md §1.2 (soft bg +
15	// solid fg). Micro typography (uppercase). `animateTo(newStatus)` worklet from
16	// §7 component inventory is intentionally deferred — the color-wash + shake
17	// transitions live in US-060 (approval/rejection animations) alongside the
18	// shared celebration/shake effects.
19	const PALETTE: Record<StatusPillStatus, { fg: string; bg: string; label: string }> = {
20	  pending: { fg: colors.warning, bg: colors.warningSoft, label: 'Pending' },
21	  approved: { fg: colors.success, bg: colors.successSoft, label: 'Approved' },
22	  rejected: { fg: colors.danger, bg: colors.dangerSoft, label: 'Rejected' },
23	  cancelled: { fg: colors.cancelled, bg: colors.cancelledSoft, label: 'Cancelled' },
24	};
25	
26	export function StatusPill({ status, label, style, testID }: StatusPillProps) {
27	  const palette = PALETTE[status];
28	  const text = label ?? palette.label;
29	  return (
30	    <View
31	      style={[styles.base, { backgroundColor: palette.bg, borderColor: palette.fg }, style]}
32	      accessibilityRole="text"
33	      accessibilityLabel={`Status: ${text}`}
34	      testID={testID}
35	    >
36	      <Text style={[textStyles.micro, { color: palette.fg }]} allowFontScaling={false}>
37	        {text}
38	      </Text>
39	    </View>
40	  );
41	}
42	
43	const styles = StyleSheet.create({
44	  base: {
45	    alignSelf: 'flex-start',
46	    paddingHorizontal: spacing.md,
47	    paddingVertical: 4,
48	    borderRadius: radii.pill,
49	    borderWidth: 2,
50	  },
51	});
